class QueueUsingStacks {
private:
    stack<long long> inStack;
    stack<long long> outStack;

public:
    void pushElement(long long x) {
        inStack.push(x);
    }

    long long popElement() {
        if (outStack.empty()) {
            while (!inStack.empty()) {
                outStack.push(inStack.top());
                inStack.pop();
            }
        }
        long long val = outStack.top();
        outStack.pop();
        return val;
    }

    long long peekElement() {
        if (outStack.empty()) {
            while (!inStack.empty()) {
                outStack.push(inStack.top());
                inStack.pop();
            }
        }
        return outStack.top();
    }

    bool isEmptyResult() {
        return inStack.empty() && outStack.empty();
    }
};

